```powershell
# Headers personnalisés
$headers = @{
    "Authorization" = "Bearer mon-token"
    "X-Api-Key" = "ma-cle"
}
$result = Invoke-RestMethod -Uri $url -Headers $headers

# Gestion des erreurs HTTP
try {
    $result = Invoke-RestMethod -Uri "https://api.example.com/data" `
        -ErrorAction Stop
} catch [System.Net.WebException] {
    $statusCode = $_.Exception.Response.StatusCode.value__
    Write-Host "Erreur HTTP : $statusCode"
} catch {
    Write-Host "Erreur : $($_.Exception.Message)"
}

# Pagination
$page = 1
do {
    $data = Invoke-RestMethod -Uri "https://api.example.com/items?page=$page"
    $data.items | ForEach-Object { Write-Host $_.name }
    $page++
} while ($data.hasMore)

# Certificats SSL auto-signés (test uniquement)
[Net.ServicePointManager]::ServerCertificateValidationCallback = { $true }
# OU PS 6+
Invoke-WebRequest -SkipCertificateCheck -Uri $url
```

```powershell
# Exemple complet : wrapper d'API
function Invoke-JsonAPI {
    param(
        [string]$Url,
        [string]$Method = 'GET',
        [hashtable]$Headers = @{},
        [object]$Body = $null
    )

    $params = @{
        Uri         = $Url
        Method      = $Method
        Headers     = $Headers
        ContentType = 'application/json'
        ErrorAction = 'Stop'
    }

    if ($Body) {
        $params.Body = $Body | ConvertTo-Json -Depth 10
    }

    try {
        Invoke-RestMethod @params
    } catch {
        [PSCustomObject]@{
            Error   = $true
            Code    = $_.Exception.Response?.StatusCode.value__
            Message = $_.Exception.Message
        }
    }
}

# Utilisation
$users = Invoke-JsonAPI -Url "https://jsonplaceholder.typicode.com/users"
$users | Select-Object name, email | Format-Table
